import React, { useState } from 'react';
import '../styles/components/WarningPanel.css';

const WarningPanel = () => {
  const [masterCaution, setMasterCaution] = useState(false);
  const [fireCaution, setFireCaution] = useState(false);
  const [warnings, setWarnings] = useState([]);

  const toggleMasterCaution = () => {
    const newState = !masterCaution;
    setMasterCaution(newState);
    if (newState) {
      setWarnings(['MASTER CAUTION', 'CHECK SYSTEMS', 'MONITOR INDICATORS']);
    } else {
      setWarnings([]);
      setFireCaution(false);
    }
  };

  const toggleFireCaution = () => {
    if (!masterCaution) {
      setMasterCaution(true);
      setWarnings(['MASTER CAUTION', 'FIRE WARNING', 'CHECK FIRE SUPPRESSION']);
    }
    const newState = !fireCaution;
    setFireCaution(newState);
    if (newState) {
      setWarnings(['FIRE WARNING', 'ENGINE FIRE DETECTED', 'ACTIVATE FIRE SUPPRESSION']);
    } else if (masterCaution) {
      setWarnings(['MASTER CAUTION', 'CHECK SYSTEMS', 'MONITOR INDICATORS']);
    } else {
      setWarnings([]);
    }
  };

  const clearAll = () => {
    setMasterCaution(false);
    setFireCaution(false);
    setWarnings([]);
  };

  return (
    <div className="warning-panel-container">
      <div className="warning-panel glass">
        <div className="panel-header">
          <span className="panel-title">WARNING PANEL</span>
          <span className="panel-model">737-800</span>
        </div>

        <div className="warning-display">
          <div className="display-screen">
            {warnings.length > 0 ? (
              <div className="warnings-list">
                {warnings.map((warning, index) => (
                  <div key={index} className="warning-item">
                    <span className="warning-indicator">⚠</span>
                    <span className="warning-text">{warning}</span>
                  </div>
                ))}
              </div>
            ) : (
              <div className="display-idle">
                <span className="idle-text">ALL SYSTEMS NORMAL</span>
              </div>
            )}
          </div>
        </div>

        <div className="panel-controls">
          <button
            className={`caution-button master-caution ${masterCaution ? 'active' : ''}`}
            onClick={toggleMasterCaution}
          >
            <span className="button-label">MASTER</span>
            <span className="button-text">CAUTION</span>
            {masterCaution && <span className="button-glow"></span>}
          </button>

          <button
            className={`caution-button fire-caution ${fireCaution ? 'active' : ''}`}
            onClick={toggleFireCaution}
          >
            <span className="button-label">FIRE</span>
            <span className="button-text">WARNING</span>
            {fireCaution && <span className="button-glow"></span>}
          </button>

          <button
            className="caution-button clear-button"
            onClick={clearAll}
          >
            <span className="button-label">CLEAR</span>
            <span className="button-text">ALL</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export default WarningPanel;
